Rules.InvariantScript:
Set(varLoading, true);
Set(varOrientacao, If(App.Width > App.Height, "Paisagem", "Retrato"));
If(
    IsBlank(varMotoristaUser),
    Set(
    varMotoristaUser,
    IfError(
        LookUp(Funcionários, 'Email Microsoft' = User().Email),
        Blank()
    )
));

// Redireciona se veio de push notification
If(
    !IsBlank(gParamServicoId) && !IsBlank(varMotoristaUser),
    With(
        {
            srvNotif: IfError(
                LookUp(Geral, 'GUID Reserva de Veículos' = GUID(gParamServicoId)),
                Blank()
            )
        },
        If(
            !IsBlank(srvNotif),
            Set(
                varServicoSelecionado,
                {
                    Tipo: "SERVICO",
                    Servico: srvNotif,
                    Troca: Blank(),
                    Manut: Blank(),
                    ManutGeral: Blank()
                }
            );
            Set(gParamServicoId, ""),

            // Não encontrou
            Notify("Serviço não encontrado ou você não tem acesso.", NotificationType.Warning, 4000)
        )
    )
);

Set(varLoading, false)

With(
    {
        nomeCompleto: Trim(User().FullName),
        partes: Split(Trim(User().FullName), " ")
    },
    "Olá, " &
    First(partes).Value &
    If(
        CountRows(partes) > 1,
        " " & Last(partes).Value,
        ""
    )
)
